mapper.select:
SELECT p.product_no, p.product_no AS id, p.company_no, p.product_name, p.product_name AS name, p.product_details, p.product_details AS content, p.original_price, p.original_price AS price, p.is_active, p.img_url, p.img_url AS thumbnail, p.large_category, p.medium_category, p.deposit, p.reg_date, c.com_name, c.com_intro AS comIntro, c.com_address AS comAddress, c.img_url AS comImgUrl, (SELECT COUNT(*) FROM product_like WHERE product_no = p.product_no) AS likeCnt, (SELECT COUNT(*) FROM product_like WHERE product_no = p.product_no AND user_id = #{loginUserId}) AS isLiked, (SELECT COUNT(*) FROM company_like WHERE company_no = p.company_no AND user_id = #{loginUserId}) AS isCompanyLiked, ( SELECT GROUP_CONCAT(DISTINCT pt_all.tag SEPARATOR ',') FROM product_tag_map ptm_all INNER JOIN product_tag pt_all ON ptm_all.tag_id = pt_all.id WHERE ptm_all.product_no = p.product_no ) AS tag FROM product p LEFT JOIN company c ON p.company_no = c.company_no
INNER JOIN product_tag_map ptm ON p.product_no = ptm.product_no INNER JOIN product_tag pt ON ptm.tag_id = pt.id
AND c.user_id = #{userid}
AND p.company_no = #{companyNo}
AND p.large_category = #{largeCategory}
AND p.medium_category = #{mediumCategory}
AND pt.tag IN
#{tag}
GROUP BY p.product_no
HAVING COUNT(DISTINCT pt.tag) = #{tagSize}
ORDER BY p.reg_date DESC

mapper.update:
UPDATE product
product_name = #{productName}, product_details = #{productDetails}, original_price = #{originalPrice}, is_active = #{isActive}, img_url = #{imgUrl}, large_category = #{largeCategory}, medium_category = #{mediumCategory}, deposit = #{deposit}
WHERE product_no = #{productNo}

mapper.select:
SELECT COUNT(*) 
FROM company_like 
WHERE user_id = #{loginUserId} AND company_no = #{companyNo}

SELECT COUNT(*) 
FROM product_like 
WHERE user_id = #{loginUserId} AND product_no = #{productNo}
